window.DAILY_NEWS_ISSUES["2026-07-14"] = {"id": "tech-2026-07-14", "section_slug": "tech", "publication_name": "我的日报·科技", "issue_date": "2026-07-14", "volume": 1, "number": 15, "date_cn": "2026 年 7 月 14 日 · 周二", "output_path": "issues/2026-07-14.html", "headlines": [{"source_item_ids": ["d03fb764fc45689d"], "kicker": "半导体 · 存储", "title_zh": "AI抢走存储芯片，全球手机出货量创2013年以来同期新低", "summary_zh": "市场机构Counterpoint数据显示，上季度全球智能手机出货量同比下滑11%，降至2013年以来的二季度最低水平。分析师将主因归于DRAM和NAND存储芯片持续涨价——厂商把产能大量转向AI计算，留给手机、PC等消费设备的存储供给减少，价格越涨越少人换机。研究机构Omdia指出，500美元及以下机型受冲击最重，存储已能占到这类手机制造成本的一半，涨价更快更猛；旗舰机存储占比也超过四分之一。前五大厂商中Oppo、Vivo、小米二季度均下滑，只有苹果（出货增长3%）和三星顶住，苹果稳价、三星重回榜首。", "read_body_zh": ["Counterpoint报告显示，2026年二季度全球智能手机出货量同比下跌11%，为2013年以来同期最低。分析师直指存储芯片价格上涨是主因：制造商普遍把产能转向支撑AI计算热潮，导致手机、PC等消费电子可用的DRAM与NAND供给减少，价格随之走高，换机意愿下降。", "涨价对低价机型的杀伤尤为明显。市场研究机构Omdia指出，售价500美元及以下的手机，存储成本如今可轻松占到整机制造成本的一半，这类机型的涨价幅度和速度都大于旗舰；而在旗舰机上，存储占比也已超过四分之一，一年间明显抬升，但高端仍有更多利润空间可挤。", "前五大厂商今年多数销量下滑，包括三星、苹果、Oppo、Vivo和小米，其中Oppo、Vivo、小米二季度均下降。苹果出货逆势增长3%，靠当前一代维持价格稳定，而多数厂商被迫涨价；三星则重回出货榜首。报道提醒，苹果的价格坚守未必能延续到未来几个月的新款iPhone。"], "pullquote": null, "ai_impact": "这轮手机疲软本质是AI算力与消费电子争抢存储产能的结果：上游晶圆厂优先服务利润更高的HBM和数据中心内存，中游手机厂被迫接受更贵的DRAM/NAND，成本最终压到下游售价和出货量。存储在手机BOM（物料清单）中占比抬升，意味着涨价周期一旦拉长，中低端市场量价齐跌的压力会持续。格局上，苹果凭品牌溢价和供应链议价力吸收成本、维持价格，三星自有存储业务反而受益于芯片涨价，两家因此扩大对Oppo、小米等的相对优势；但苹果新iPhone若跟进涨价，这种领先未必稳固。存储超级周期正成为决定手机厂盈利和排位的关键变量。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/gadgets/2026/07/apple-and-samsung-benefit-as-memory-shortage-pushes-smartphone-shipments-to-historic-lows"}], "relevance_score": 96, "importance_score": 91}, {"source_item_ids": ["273494efbcc066db"], "kicker": "AI基建 · 资本", "title_zh": "押注AI热潮，美国数据中心开发商密集抛售数百亿美元股权", "summary_zh": "多位知情人士透露，今年夏季美国多家数据中心建设与运营企业正联合投行，计划出售价值数百亿美元的多数股权，借AI热潮变现离场。正在接洽的标的包括Netrality、DataBank、Edged、EdgeCore数字基础设施等企业，布局覆盖凤凰城至亚特兰大等地。当前算力需求持续旺盛，数据中心成为热门资产，投行正积极向私募股权机构推介这类项目。", "read_body_zh": ["据多位知情人士透露，2026年夏季，全美多家数据中心建设及运营企业正联合投资银行，计划出售公司价值数百亿美元的多数股权。报道将这一动作描述为开发商借人工智能行业热潮“变现离场”，即在估值高位把控股权益转让出去。", "投行正在接洽的股权转让标的包括Netrality数据中心、DataBank、Edged以及EdgeCore数字基础设施等企业，这些公司的产业布局覆盖从凤凰城到亚特兰大的多个地区，均为近年算力扩张的重点承接地。", "报道称，当前算力需求持续旺盛，数据中心已成为资本市场的热门资产；投行正把这类标的大力推介给私募股权机构（PE，即通过收购未上市公司股权获利的投资机构），显示买方需求同样活跃。"], "pullquote": null, "ai_impact": "这批集中出售是AI基建从“拼命建”转向“资产变现”的明确信号。过去两年资本疯狂涌入数据中心，赌的是算力长期短缺；如今开发商趁需求和估值都在高位卖出控股权，既是锁定建设期收益，也隐含对未来供给过剩和回报下滑的对冲。接盘方多为私募股权机构，意味着数据中心正从成长型科技资产变成偏基础设施的现金流资产，定价逻辑向租金、电力和长约客户倾斜。若成交价持续走高，说明市场仍信算力紧缺；一旦估值松动，则可能是这轮AI基建周期见顶的早期迹象，值得作为观察资本退出窗口的风向标。", "sources": [{"name": "36氪", "url": "https://36kr.com/newsflashes/3894773393210631?f=rss"}], "relevance_score": 92, "importance_score": 85}, {"source_item_ids": ["4758ec450c439786"], "kicker": "诉讼 · AI硬件", "title_zh": "苹果起诉OpenAI：前工程师借漏洞窃取未发布硬件机密", "summary_zh": "苹果上周五提起诉讼，指控OpenAI与其前员工合谋窃取商业秘密，并寻求禁令阻止OpenAI使用相关机密。据诉状，在苹果工作八年、参与多项敏感产品研发的工程师Chang Liu于2026年1月跳槽OpenAI，2月发现一个苹果当时未知的“认证漏洞”，得以用本应归还的苹果工作笔记本访问公司共享网络文件夹。他没有上报，而是在数周内下载了大量未发布产品资料、工程演示、技术规格和电路板机密文件，部分被明确标注为机密。苹果称漏洞被发现后已很快修复，且未见被广泛利用。", "read_body_zh": ["苹果于上周五提起诉讼，要求对OpenAI处以重罚，并寻求多项禁令，阻止其使用被前员工窃取的机密信息。诉状称，OpenAI与苹果前员工合谋“走非法捷径”，意图快速推出一条像iPhone一样畅销的AI硬件产品线。", "苹果称，涉事工程师Chang Liu在苹果工作八年、参与过最敏感的产品研发，于2026年1月离职加入OpenAI。2月9日，他发现一个苹果当时并不知情的“认证漏洞”，得以用一台本应归还的苹果配发笔记本访问公司共享网络文件夹。", "据诉状，Liu没有上报漏洞，而是在数周内一边为OpenAI开发硬件，一边下载了数十份苹果机密硬件文件，包括未发布产品的详细信息、工程演示、技术规格，以及一份关于复杂电路板的演示——苹果称后者“对任何做硬件的人都极具价值”。苹果在脚注中确认漏洞被发现后已很快修复，且未见被广泛利用。"], "pullquote": null, "ai_impact": "这起诉讼的看点不在个案窃密，而在两家巨头围绕AI硬件的正面竞争。OpenAI正联手多名苹果前员工押注一款“AI时代的iPhone”，直接切入苹果最核心的硬件腹地；苹果借诉讼既想保住未发布产品和电路板等设计机密，也是在为人才大规模流向AI公司设立法律警戒线。案件若坐实，可能收紧行业对“离职工程师带走什么算商业秘密”的判定，抬高AI硬件创业挖角苹果的法律成本；即便最终和解，禁令诉求本身也会拖慢OpenAI硬件计划的节奏，并让科技公司重新审视设备回收、权限注销等内部安全流程。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/tech-policy/2026/07/apple-sues-openai-after-ex-engineer-allegedly-used-bug-to-steal-trade-secrets"}], "relevance_score": 87, "importance_score": 86}, {"source_item_ids": ["4652e6eb71b5a50e"], "kicker": "半导体 · 产能", "title_zh": "博世首座美国芯片厂试产，押注碳化硅与本土制造", "summary_zh": "德国汽车零部件与芯片制造商博世周一表示，其首座美国半导体工厂已开始试生产，并与美国商务部敲定一项2.25亿美元协议，以加强碳化硅芯片的本土制造能力。该厂由博世2023年从TSI Semiconductors收购的加州罗斯维尔工厂改造而来，含商务部资金在内总投入达20亿美元，计划今年晚些时候开始商业化量产。报道指出，在特朗普任内，一些车企和零部件供应商扩大在美制造，以规避高关税并防范地缘政治风险。", "read_body_zh": ["博世周一宣布，公司首座美国半导体工厂已进入试生产阶段，并与美国商务部敲定一项价值2.25亿美元的协议，目标是加强碳化硅（SiC）芯片的国内制造能力。碳化硅是新能源汽车电控、快充等场景的关键功率半导体材料。", "这座工厂位于加州罗斯维尔，由博世2023年从TSI Semiconductors收购后改造而来，包括美国商务部拨款在内，总投入达20亿美元。博世表示，工厂将于今年晚些时候开始商业化量产。", "报道将此举置于更大的产业迁移背景下：在特朗普总统任内，一些汽车制造商和零部件供应商纷纷扩大在美国的制造业务，一方面规避高昂关税，一方面防范地缘政治风险。博世此次落子，正是这一趋势中的汽车芯片本土化案例。"], "pullquote": null, "ai_impact": "博世这座工厂是政策、地缘和产业趋势合力的产物，看点在汽车芯片的“去全球化”。碳化硅是电动车三电系统的核心功率器件，需求随电动化上升，博世自建产能等于把关键料件的供给攥在自己手里，减少对外部代工和跨境供应链的依赖。2.25亿美元政府补贴加规避关税的动机，说明美国正用财政手段把汽车芯片制造拉回本土，这会推高车企在美建立“就近供货”体系的动力，也让欧洲、亚洲现有SiC产能面临订单分流。对整个行业，这是补贴驱动的重复建设与产能区域化的又一步——短期抬高成本，长期可能形成多个割裂的本地供应圈，削弱以往靠集中代工换取的成本效率。", "sources": [{"name": "36氪", "url": "https://36kr.com/newsflashes/3894787976756229?f=rss"}], "relevance_score": 90, "importance_score": 84}, {"source_item_ids": ["5ac9928d1fa48f59"], "kicker": "大模型 · 企业AI", "title_zh": "纳德拉警告：用封闭模型的企业，正把专有知识拱手交出", "summary_zh": "微软CEO纳德拉周日发文警告，使用OpenAI、Anthropic等封闭模型的企业其实“为智能付了两次费”——一次用钱买token，一次用更宝贵的专有知识。他指出，模型会从提示词、工具调用尤其是人工纠错中学习，把企业独有的业务know-how蒸馏成“竞争对手买不到的知识”。纳德拉主张企业保留数据所有权、在云上自建“专有学习环境”，并搭建可在不同模型间切换的编排层。报道还提到，上月经Vercel网关路由的流量中，开放模型已占29%。", "read_body_zh": ["微软CEO纳德拉周日发表博文，加入“封闭模型如同特洛伊木马”的担忧阵营。他认为，当创业公司和企业使用来自OpenAI、Anthropic等实验室的AI模型时，这些实验室会不断获得客户最敏感的业务信息，进而可能变成客户自己的竞争对手。", "纳德拉提出“为智能付两次费”的说法：企业明知要为token用量花钱，却在不知不觉中交出更宝贵的专有知识。他强调，模型会从“排放物”中学习——人们写的提示、智能体调用的工具，尤其是模型出错时人工做出的纠正，“每一次纠正都会被蒸馏成机构级的know-how”。", "他的解法是让企业“保留数据所有权”，在云上自建“专有学习环境”（其数据往往已存于云端，也顺势指向微软自家Azure），并搭建可在不同供应商模型间自由切换的“编排层”。报道援引数据佐证这一趋势：上月经Vercel网关路由的全部流量中，开放模型已占到29%。"], "pullquote": {"text": "在消费智能的同时，你也在创造智能；而你所创造的，理应归你所有。", "cite": "微软CEO 萨提亚·纳德拉"}, "ai_impact": "纳德拉这番话表面谈数据主权，底层是企业AI架构与商业格局之争。核心逻辑是：模型能力越强，企业喂进去的专有数据越多，封闭大模型厂商就越可能反向蚕食客户的业务。他推的“自有学习环境加多模型编排”，实质是把企业往开源模型、本地部署和微软云上迁——既削弱OpenAI等对客户数据的独占，又把流量导向Azure；微软身兼OpenAI和Anthropic投资方却公开唱多开源，用意耐人寻味。开放模型已占Vercel网关29%流量，说明“能自控、更便宜、够用九成”的开源方案正在真实分流。若这一叙事扩散，封闭模型的护城河将从“能力最强”被迫转向“数据承诺更可信”，企业AI的议价权和价值分配都会随之重排。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/satya-nadella-has-issued-a-shocking-warning-to-companies-using-ai"}], "relevance_score": 91, "importance_score": 83}], "briefs": [{"source_item_ids": ["1f20765fb8d66748"], "title_zh": "奥特曼与马斯克互怼，太空数据中心被指短期难成生意", "summary_zh": "奥特曼与马斯克周末在社交媒体互呛，把太空数据中心“愿景与现实的差距”再度推上台面。马斯克指奥特曼是骗子，奥特曼回击称对方才是在向公开市场投资者兜售“短期太空数据中心”。SpaceX计划发射轨道数据中心做AI推理，是其2万亿美元估值的主要支撑；但多位专家（含创业者、谷歌轨道计算团队和工程师）认为，在火箭大幅降价、能低成本量产高功率卫星之前难以规模化，真正商业化更可能要等到2030年代。Starship第13次试飞最快7月16日进行。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/sam-altmans-space-data-center-trash-talk-is-what-most-experts-already-believe"}], "relevance_score": 84, "importance_score": 70}, {"source_item_ids": ["a109e79d3f01e03b"], "title_zh": "Uber自建传感器车队AV Labs，为自动驾驶合作攒数据筹码", "summary_zh": "Uber首席产品官Sachin Kansal受访透露，公司半年前成立了名为AV Labs的业务单元，运营一支独立于普通司机网络、装有传感器的车队，专门采集大规模驾驶数据。Uber称此举是为强化与自动驾驶合作方的关系，但它同时与Waymo等合作方直接竞争，掌握数据层能带来议价权和更多选择空间。采访还涉及Uber向旅行（接入Expedia酒店）、司机金融（Uber Pro借记卡）等方向的扩张，以及是否走向“超级App”的开放问题。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/ubers-product-chief-on-hotels-robotaxis-and-why-the-company-doesnt-want-to-be-everything-for-everyone"}], "relevance_score": 78, "importance_score": 68}, {"source_item_ids": ["c5fece3c75266539"], "title_zh": "字节被曝探索自动驾驶，Seed世界模型团队牵头、官方否认有计划", "summary_zh": "36氪独家报道，字节跳动正探索进入自动驾驶领域，项目由Seed旗下周畅的世界模型团队负责，方向可能涉及无人物流，归属火山引擎汽车行业线。多位产业人士称项目处于早期筹备，字节已向头部辅助/自动驾驶人才发出邀约。世界模型与自动驾驶技术路线有交叠，也被视为字节切入具身智能的潜在跳板。但字节回应称，其在物理AI等领域有早期研究和探索，“并没有做智能驾驶业务的计划”，落地证据仍不足。", "sources": [{"name": "36氪", "url": "https://36kr.com/p/3893815451417347?f=rss"}], "relevance_score": 84, "importance_score": 74}, {"source_item_ids": ["7f1cd900d4f6645c", "dec709fc7adbdbc0"], "title_zh": "iOS 27首个公测版发布，重做的Siri AI开放试用", "summary_zh": "苹果发布iOS 27及iPadOS 27、watchOS 27、macOS 27等公开测试版，正式版预计今秋推出。本次最大新功能是几经推迟、由AI重做的Siri：用户先说出要做什么，Siri再跨App和网络信息去执行。The Verge记者实测约一个月，认为它“真的能用”，可读取屏幕内容、把邮件里的日程批量加入日历，已让他大多数场景不再打开浏览器。但目前仅苹果自家App接入，第三方需适配entities和intents，且自然语言到具体动作的转换仍有不少卡顿。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/tech/964307/apple-public-betas-ios-27-siri-ai"}, {"name": "The Verge", "url": "https://www.theverge.com/tech/964714/siri-ai-public-beta-preview-ios-27-hands-on"}], "relevance_score": 85, "importance_score": 73}, {"source_item_ids": ["db86ade1bf8a4298"], "title_zh": "第三方实测：苹果新语音API准确率胜过Whisper", "summary_zh": "开发商Inscribe在同一台M2 Pro上对五款本地语音引擎做基准测试，结果显示苹果随iOS 26/macOS 26推出的新API SpeechAnalyzer，在LibriSpeech干净和嘈杂语音上均击败其搭载的所有Whisper模型（含最大的Whisper Small），速度约为后者三倍。相比被替代的旧API SFSpeechRecognizer，词错率降低约3.5至4倍（干净语音从9.02%降到2.12%）。Whisper仍有语言覆盖更广、跨平台可用的优势，但英文本地转写上“Whisper默认最准”的时代已结束。测试原始转写公开可复核。", "sources": [{"name": "Hacker News", "url": "https://get-inscribe.com/blog/apple-speech-api-benchmark.html"}], "relevance_score": 83, "importance_score": 67}, {"source_item_ids": ["b5e0fe554caddf2f"], "title_zh": "软银携手Sierra，在日本独家落地AI客服", "summary_zh": "软银集团与AI客服公司Sierra达成战略合作，自7月14日起软银成为Sierra在日本的独家合作方，将推出由智能AI代理驱动的客户服务。软银旗下线上手机品牌Linemo已接入相关技术，公司计划后续扩展到软银、Y!mobile等自有品牌及集团其他业务线。这是又一个已进入实际生产部署的大模型商业化案例，目前外溢范围仍限于软银体系内部。", "sources": [{"name": "36氪", "url": "https://36kr.com/newsflashes/3894788367613191?f=rss"}], "relevance_score": 65, "importance_score": 61}, {"source_item_ids": ["75b6ca41afa7b318"], "title_zh": "谷歌把Gemini塞进Waze：对话搜目的地、个性化路线、摩托车模式", "summary_zh": "谷歌旗下导航应用Waze上线多项AI新功能，部分由Gemini驱动。应用可根据用户出行历史和城市交通规律推荐个性化路线（如偏好高速者优先看到），该功能已在全球iOS和安卓上线；用户还能用Gemini对话式搜索目的地（如“找家现在营业的咖啡店”），目前面向全球beta用户推送。此外新增用AI适配两轮车捷径与限行的摩托车模式，以及可对话上报路况、减少语音打扰的“少啰嗦”模式。此举也强化Waze与Apple地图的竞争。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/waze-adds-new-ai-powered-features-and-customization-updates"}], "relevance_score": 77, "importance_score": 68}, {"source_item_ids": ["46e1618d19f4c645"], "title_zh": "Uber游说自动驾驶法案，与合作方Waymo正面交锋", "summary_zh": "华盛顿特区一项拟允许无人车运营的法案，成为Uber与Waymo的角力场。Uber反对该法案，主张机器人出租车必须接入同时使用人类司机的网约车平台，认为直接放开会让Waymo形成事实垄断、并挤走人类司机；Waymo支持法案，称其能在保障公共交通和就业的同时安全部署无人车。两家将于周一听证会各自陈情。法案还拟对无人车每英里征收0.15美元税，特斯拉、Lyft、工会等多方都将出席。Uber既投资、合作又与Waymo直接竞争，冲突凸显其自动驾驶策略的两难。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/ubers-robotaxi-lobbying-effort-has-put-it-on-a-collision-course-with-waymo"}], "relevance_score": 80, "importance_score": 72}, {"source_item_ids": ["d664970ba014e156"], "title_zh": "防守方反用提示注入：“上下文炸弹”让攻击型AI自我瘫痪", "summary_zh": "安全公司Tracebit发现，把提示注入和密码、密钥等机密放在一起，常能让AI黑客智能体在得手前自行停摆。手法是植入触发模型安全护栏的禁忌指令（如索要炭疽制备步骤，或对中国产模型提及六四“坦克人”），一旦进入上下文，模型便持续拒答，研究者称之为“上下文炸弹”。在对Opus 4.8、Gemini 3.1 Pro、GLM 5.2等五款模型、152次攻击的测试中，植入一个诱饵密钥使智能体夺取账户管理员权限的比例从57%降至5%；Opus 4.8更从93%降到全部失败。该方法仍处早期测试。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/security/2026/07/now-defenders-are-embracing-the-prompt-injection-too"}], "relevance_score": 79, "importance_score": 69}, {"source_item_ids": ["7fc6b864d0e22e8c"], "title_zh": "Claude在印度启用卢比定价，尚未接入UPI", "summary_zh": "Anthropic开始为其美国以外最大市场印度提供卢比计价的订阅方案，部分用户已在网站和App看到本地价格。但公司尚未支持印度广泛使用的UPI即时支付网络，用户仍需用银行卡或苹果、谷歌应用商店结算，这一点落后于已支持UPI的OpenAI。印度占全球Claude使用量的5.8%，是仅次于美国的第二大市场。定价上，Claude Pro年付约合每月21美元，略高于美国的17美元。此前Anthropic已在印度设立办公室并牵手Infosys、TCS拓展企业业务。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/07/13/anthropic-starts-localizing-claude-pricing-for-india-its-biggest-market-after-the-us"}], "relevance_score": 72, "importance_score": 66}, {"source_item_ids": ["cf581b9a5fd7488b"], "title_zh": "英伟达RTX Spark AIPC中国首秀，笔记本跑百GB大型场景", "summary_zh": "英伟达首款CPU平台RTX Spark在上海Bilibili World完成中国首秀，展示机为基于该平台的联想YOGA Pro 15。它把最高20核Grace CPU、Blackwell RTX GPU和最高128GB统一内存整合进同一平台，FP4算力最高达1 Petaflop，运行Windows on Arm。现场演示流畅打开超100GB的虚幻5城市场景，并跑原生Arm版《永劫无间》，离电性能几乎不掉档。统一内存让CPU与GPU共用内存池，使轻薄本能接手过去属于工作站的任务。首批产品预计今年秋季上市；报道带有体验和推广色彩。", "sources": [{"name": "爱范儿", "url": "https://www.ifanr.com/1671945"}], "relevance_score": 82, "importance_score": 69}, {"source_item_ids": ["c3e8b7dbe4480f59"], "title_zh": "三星健康被曝：不同意用数据训练AI，云端备份将被删除", "summary_zh": "有报道指出，三星在Samsung Health应用设置深处新增“同意将健康数据用于AI训练与建模”开关，用户须同意才能备份数据。尝试关闭时，应用会警告：撤回同意后将无法与三星账户同步健康数据，且相关数据除法律要求保留外将被删除。三星计划采集睡眠、用药、病历和生理周期四类信息，并称部分数据可能由人工（含员工和第三方承包商）审阅。该功能正值搭载生成式AI的Galaxy Watch 9与One UI 9 Watch上线之际推出。", "sources": [{"name": "Hacker News", "url": "https://neow.in/cWsyMTV3"}], "relevance_score": 73, "importance_score": 71}], "discarded": [{"source_item_ids": ["b5ea6925b84ebcdb"], "reason": "券商研报主要是对下半年AI投资主题和板块机会的观点判断，没有新的公司行动、产能、订单、价格或采用数据，事件性和可验证增量不足。", "relevance_score": 57, "importance_score": 43}, {"source_item_ids": ["ad32d226e472d538"], "reason": "早报聚合稿混合多条事件，包含历史索引已发布的台积电2纳米、Grok代码上传等旧闻，也复述本批已有独立来源的字节自动驾驶；其余爆料缺少足够独立核验，不应把合集包装成新条目。", "relevance_score": 66, "importance_score": 38}, {"source_item_ids": ["6bd419d2cab2df5e"], "reason": "抓取正文只有重定向提示，无法基于全文确认观点、事实与证据；标题又属于评论性争议，信息不足以入选。", "relevance_score": 38, "importance_score": 28}, {"source_item_ids": ["22a4ca723b2a161f"], "reason": "个人博客主要讨论对大模型热潮的态度与主观使用感受，缺少新产品、基准、商业采用或产业链事实，难以形成日报事件。", "relevance_score": 51, "importance_score": 39}], "merged_sources": [{"source_item_ids": ["7f1cd900d4f6645c", "dec709fc7adbdbc0"], "reason": "同一事件：iOS 27首个公开测试版发布及其中Siri AI的实测报道。"}]};
